const items = $('DATA_download').all();

if (items.length === 0) return [];

const latestItem = items[items.length - 1];

return [
  {
    json: {
      pic: latestItem.json.pic,
      url: latestItem.json.url,
      message: latestItem.json.message
    }
  }
];

